import { Ref, ReadonlyRef } from "@hoge1e3/ref";
export interface ReadonlyPathRef<T> extends ReadonlyRef<T> {
    join<N>(path: ((t: T) => N)): ReadonlyPathRef<N>;
    join<K extends keyof T>(path: K): PathRef<T[K]>;
}
export interface PathRef<T> extends Ref<T> {
    join<N>(path: ((t: T) => N)): ReadonlyPathRef<N>;
    join<K extends keyof T>(path: K): PathRef<T[K]>;
}
export type PathComponent<T, N> = ((t: T) => N) | (N extends T[keyof T] ? {
    [K in keyof T]: T[K] extends N ? K : never;
}[keyof T] : never);
export type Path<R, T> = null | ConsPath<R, any, T>;
export interface ConsPath<R, M, T> {
    left: Path<R, M>;
    right: PathComponent<M, T>;
}
export declare function create<T>(r: Ref<T>): PathRef<T>;
